from __future__ import annotations

import httpx
import logging
import openai
from typing import Any, Iterator

from fitz_ai.llm.auth import AuthProvider
from fitz_ai.llm.auth.httpx_auth import HTTPXAuth
from fitz_ai.llm.providers.base import (
    ChatProvider,
    EmbeddingProvider,
    StreamingChatProvider,
    VisionProvider,
)

CHAT_MODELS = {
    "default": "gpt-4-turbo",
}
EMBEDDING_MODEL = "text-embedding-3-small"
VISION_MODEL = "gpt-4-vision-preview"

class OpenAIChat(ChatProvider):
    def __init__(self, auth: AuthProvider, model: str | None, tier: ModelTier, base_url: str | None, models: dict[ModelTier, str] | None) -> None:
        self._client = openai.OpenAI(
            api_key=auth.get_headers().get("Authorization", "").replace("Bearer ", "") if auth.get_headers().get("Authorization") else None,
            base_url=base_url or "https://api.openai.com/v1",
            http_client=httpx.AsyncClient(auth=HTTPXAuth(auth)),
        )
        self._model = model or CHAT_MODELS[tier]

    def chat(self, messages: list[dict[str, Any]]) -> str:
        response = self._client.chat.completions.create(
            model=self._model,
            messages=messages,
        )
        return response.choices[0].message.content

    def chat_stream(self, messages: list[dict[str, Any]]) -> Iterator[str]:
        stream = self._client.chat.completions.create(
            model=self._model,
            messages=messages,
            stream=True,
        )
        for chunk in stream:
            if chunk.choices and chunk.choices[0].delta.content is not None:
                yield chunk.choices[0].delta.content

class OpenAIEmbedding(EmbeddingProvider):
    def __init__(self, auth: AuthProvider, model: str | None, dimensions: int | None, base_url: str | None) -> None:
        self._client = openai.OpenAI(
