from __future__ import annotations

import httpx
import json
import logging
import re
from typing import Any, Iterator

from fitz_ai.llm.providers.base import (
    ChatProvider,
    EmbeddingProvider,
    RerankProvider,
    StreamingChatProvider,
    VisionProvider,
)

CHAT_MODELS = {
    "default": "llama3:latest",
}
EMBEDDING_MODEL = "mxbai-embed-large"
RERANK_MODEL = "reranker-mlcross-encoder-tiny"
VISION_MODEL = "llava:latest"
DEFAULT_BASE_URL = "http://localhost:11434"


class OllamaChat(ChatProvider):
    def __init__(self, model: str | None, tier: ModelTier, base_url: str | None, models: dict[ModelTier, str] | None) -> None:
        self._client = httpx.AsyncClient(base_url=base_url or DEFAULT_BASE_URL)
        self._model = model or CHAT_MODELS[tier]

    def chat(self, messages: list[dict[str, Any]]) -> str:
        response = self._client.post(
            "/api/generate",
            json={
                "model": self._model,
                "prompt": messages[-1]["content"] if messages else "",
                "stream": False,
            },
        )
        data = response.json()
        return data["response"]

    def chat_stream(self, messages: list[dict[str, Any]]) -> Iterator[str]:
        stream = self._client.post(
            "/api/generate",
            json={
                "model": self._model,
                "prompt": messages[-1]["content"] if messages else "",
                "stream": True,
            },
            stream=True,
        )
        for chunk in stream.iter_text():
            data = json.loads(chunk)
            if "response" in data:
                yield data["response"]

    def __del__(self) -> None:
        try:
            self._client.aclose()
        except Exception:
            pass

class OllamaEmbedding(EmbeddingProvider):
    def __init__(self, model: str | None, base_url: str | None, num_ctx: int | None) -> None:
        self._client = httpx.AsyncClient(base_url=base_url or DEFAULT_BASE_URL)
        self._model = model or EMBEDDING_MODEL
        self._num_ctx = num_ctx

    def _resolve_prefixes(self) -> dict[str, str]:
        return {
            "embedding": "embed",
            "sentence": "sentence-transformer",
        }

    def _apply_prefix(self, text: str, task_type: str | None) -> str:
        prefixes = self._resolve_prefixes()
        prefix_key = task_type or "embedding"
        if prefix_key in prefixes:
            return f"{prefixes[prefix_key]}:{text}"
        return text

    def embed(self, text: str) -> list[float]:
        prefixed_text = self._apply_prefix(text, None)
        response = self._client.post(
            "/api/embeddings",
            json={
                "model": self._model,
                "prompt": prefixed_text,
            },
        )
        data = response.json()
        return data["embedding"]

    def embed_batch(self, texts: list[str]) -> list[list[float]]:
        batch_results = []
        for text in texts:
            batch_results.append(self.embed(text))
        return batch_results

    def dimensions(self) -> int:
        # Ollama embedding models typically output 512 or larger vectors
        return 512

    def __del__(self) -> None:
        try:
            self._client.aclose()
        except Exception:
            pass

class OllamaRerank(RerankProvider):
    def __init__(self, model: str | None, base_url: str | None) -> None:
        self._client = httpx.AsyncClient(base_url=base_url or DEFAULT_BASE_URL)
        self._model = model or RERANK_MODEL

    def rerank(self, query: str, documents: list[str], top_n: int | None) -> list[RerankResult]:
        results = []
        for doc in documents:
            score = self._score_document(query, doc)
            results.append(RerankResult(document=doc, score=score))
        # Sort by descending scores
        results.sort(key=lambda r: r.score, reverse=True)
        return results[:top_n] if top_n else results

    def _score_document(self, query: str, document: str) -> float:
        response = self._client.post(
            "/api/rerank",
            json={
                "model": self._model,
                "query": query,
                "documents": [document],
            },
        )
        content = response.text  # Raw string
        return self._parse_score(content)

    def _parse_score(self, content: str) -> float:
        try:
            data = json.loads(content)
            if isinstance(data, dict) and "results" in data and len(data["results"]) > 0:
                return data["results"][0].get("relevance_score", 0.0)
        except Exception as e:
            logging.warning(f"Failed to parse rerank score: {e}")
        return 0.0

    def __del__(self) -> None:
        try:
            self._client.aclose()
        except Exception:
            pass

class OllamaVision(VisionProvider):
    def __init__(self, model: str | None, base_url: str | None) -> None:
        self._client = httpx.AsyncClient(base_url=base_url or DEFAULT_BASE_URL)
        self._model = model or VISION_MODEL

    def describe_image(self, image_base64: str, prompt: str | None) -> str:
        response = self._client.post(
            "/api/generate",
            json={
                "model": self._model,
                "prompt": prompt or "Describe this image.",
                "images": [image_base64],
                "stream": False,
            },
        )
        data = response.json()
        return data["response"]

    def __del__(self) -> None:
        try:
            self._client.aclose()
        except Exception:
            pass

