import threading
from typing import Any, Callable, Iterator, Protocol, Set, TypeVar, Union


BenchmarkHook = Protocol[
    [str, str, str, tuple[Any], dict[str, Any]],
    Any,
]
CachingHook = Protocol[
    [str, str, str, tuple[Any], dict[str, Any]],
    Any,
]


