unregister_hook: Callable[[BenchmarkHook], None] = lambda hook: None
clear_hooks: Callable[[], None] = lambda: None
has_hooks: Callable[[], bool] = lambda: False
g_get_hooks: Callable[[], list[BenchmarkHook]] = lambda: []


NO_CACHE = object()

class InstrumentedProxy:
    def __init__(self, target: Any, layer: str, plugin_name: str, methods_to_track: set[str] | None = None) -> None:
        self._target = target
        self._layer = layer
        self._plugin_name = plugin_name
        if methods_to_track is not None:
            self._methods_to_track = methods_to_track
        else:
            # By default, track all public methods that are callable and not dunder methods
            self._methods_to_track = {
                name for name in dir(target) 
                if not name.startswith("_") and callable(getattr(target, name))
            }

    def __getattr__(self, name: str) -> Any:
        attr = getattr(self._target, name)
        # Only wrap methods we are tracking
        if name in self._methods_to_track and callable(attr):
            return self._wrap_method(attr, name)
        return attr

    def _wrap_method(self, method: Callable, method_name: str) -> Callable:
        @functools.wraps(method)
        def wrapper(*args: Any, **kwargs: Any) -> Any:
            # Get hooks if they exist
            hooks = get_hooks()
            context = None
            error = None
            result = None
            try:
                for hook in hooks:
                    if hasattr(hook, "on_call_start"):
                        context = hook.on_call_start(self._layer, self._plugin_name, method_name, args, kwargs)
                # Execute the wrapped function
                result = method(*args, **kwargs)
            except Exception as e:
                error = e
                raise  # Re-raise to preserve original behavior
            finally:
                for hook in hooks:
                    if hasattr(hook, "on_call_end"):
                        hook.on_call_end(context, result, error)
            return result
        return wrapper

    def __repr__(self) -> str:
        return f"InstrumentedProxy({self._target!r}, layer={self._layer!r}, plugin_name={self._plugin_name!r})"

    def __str__(self) -> str:
        return self.__repr__()

def maybe_wrap(target: Any, layer: str, plugin_name: str, methods_to_track: set[str] | None = None) -> Any:
    if has_hooks():
        return InstrumentedProxy(target, layer, plugin_name, methods_to_track)
    else:
        return target

def wrap(target: Any, layer: str, plugin_name: str, methods_to_track: set[str] | None = None) -> InstrumentedProxy:
    return InstrumentedProxy(target, layer, plugin_name, methods_to_track)

